import React from 'react';
import { Line } from 'react-konva';

const PenTool = ({ points, strokeWidth = 2, stroke = '#000000' }) => {
  // Smooth the points using Catmull-Rom spline for better curves
  const smoothPoints = (rawPoints) => {
    if (rawPoints.length < 4) return rawPoints;

    const smoothed = [];

    // Add the first point
    smoothed.push(rawPoints[0], rawPoints[1]);

    // Process points in pairs (x, y)
    for (let i = 2; i < rawPoints.length - 2; i += 2) {
      const x0 = rawPoints[i - 2] || rawPoints[i];
      const y0 = rawPoints[i - 1] || rawPoints[i + 1];
      const x1 = rawPoints[i];
      const y1 = rawPoints[i + 1];
      const x2 = rawPoints[i + 2];
      const y2 = rawPoints[i + 3];
      const x3 = rawPoints[i + 4] || x2;
      const y3 = rawPoints[i + 5] || y2;

      // Catmull-Rom interpolation
      for (let t = 0; t <= 1; t += 0.25) {
        const t2 = t * t;
        const t3 = t2 * t;

        const x = 0.5 * (
          (2 * x1) +
          (-x0 + x2) * t +
          (2 * x0 - 5 * x1 + 4 * x2 - x3) * t2 +
          (-x0 + 3 * x1 - 3 * x2 + x3) * t3
        );

        const y = 0.5 * (
          (2 * y1) +
          (-y0 + y2) * t +
          (2 * y0 - 5 * y1 + 4 * y2 - y3) * t2 +
          (-y0 + 3 * y1 - 3 * y2 + y3) * t3
        );

        smoothed.push(x, y);
      }
    }

    // Add the last point
    if (rawPoints.length >= 2) {
      smoothed.push(rawPoints[rawPoints.length - 2], rawPoints[rawPoints.length - 1]);
    }

    return smoothed;
  };

  const finalPoints = points.length > 6 ? smoothPoints(points) : points;

  return (
    <Line
      points={finalPoints}
      stroke={stroke}
      strokeWidth={strokeWidth}
      tension={0.5}
      lineCap="round"
      lineJoin="round"
      globalCompositeOperation="source-over"
      perfectDrawEnabled={false}
      shadowForStrokeEnabled={false}
    />
  );
};

export default PenTool;
